commands_run.command:
node --input-type=module <<'NODE'
import { readFileSync, writeFileSync } from 'node:fs';
const path = 'evals/effectiveness/reports/test-coverage-002/treatment-result.json';
const result = JSON.parse(readFileSync(path, 'utf8'));
result.validation_logs = [];
result.validation_log_paths = [];
result.validation_command_results = [
  { command: 'npm test', status: 'NOT_RUN', passed: false, evidence: 'validation command log missing' },
  { command: 'npm run coverage:contract', status: 'NOT_RUN', passed: false, evidence: 'validation command log missing' }
];
result.coverage_contract_passed = false;
result.first_failed_stage = 'dev_worker';
result.corrected_failure_category = 'TEST_COVERAGE_002_DEV_WORKER_TURN_NO_EVENT_TIMEOUT';
result.failure_category_was_stale_or_inconsistent = result.failure_category !== result.corrected_failure_category;
writeFileSync(path, `${JSON.stringify(result, null, 2)}\n`, 'utf8');
NODE
